function render() {
  if (state.screen === "auth") renderAuth();
  else if (state.screen === "onboard") renderOnboard();
  else if(state.appSection==="messages") renderMessages();
  else if(state.appSection==="household") renderHousehold();
  else if(state.appSection==="life") renderLifeHub();
  else renderDashboard();
}

function brand() { return `<div class="brand"><span class="brand-mark">⌂</span> RoomBridge</div>`; }
function mainNav(active) { return `<nav class="nav"><button class="${active==='roommates'?'active':''}" id="roommateNav">${icon('spark')} Roommates</button><button class="${active==='housing'?'active':''}" id="housingNav">⌂ Housing</button><button class="${active==='messages'?'active':''}" id="messagesNav">${icon('chat')} Messages</button><button class="${active==='household'?'active':''}" id="householdNav">♧ Household</button><button class="${active==='life'?'active':''}" id="lifeNav">◎ Life hub</button></nav>`; }
function bindMainNav(){document.querySelector('#roommateNav')?.addEventListener('click',()=>{state.appSection='discover';state.discovery='roommates';renderDashboard()});document.querySelector('#housingNav')?.addEventListener('click',()=>{state.appSection='discover';state.discovery='housing';renderListings()});document.querySelector('#messagesNav')?.addEventListener('click',()=>{state.appSection='messages';renderMessages()});document.querySelector('#householdNav')?.addEventListener('click',()=>{state.appSection='household';renderHousehold()});document.querySelector('#lifeNav')?.addEventListener('click',()=>{state.appSection='life';renderLifeHub()});document.querySelector('#securityCenter')?.addEventListener('click',openSecurityCenter)}

const authStore = {
  users: () => JSON.parse(localStorage.getItem("rbAccounts") || "[]"),
  save(users) { localStorage.setItem("rbAccounts", JSON.stringify(users)); },
  async hash(password, salt) {
    const bytes = new TextEncoder().encode(`${salt}:${password}`);
    const digest = await crypto.subtle.digest("SHA-256", bytes);
    return [...new Uint8Array(digest)].map(b => b.toString(16).padStart(2, "0")).join("");
  },
  code() { return String(Math.floor(100000 + Math.random() * 900000)); },
  session(account) {
    const safe = { id: account.id, name: account.name, email: account.email, phone: account.phone || "", emailVerified: account.emailVerified, phoneVerified: account.phoneVerified, institutionVerified: account.institutionVerified || false };
    sessionStorage.setItem("rbSession", JSON.stringify(safe));
    return safe;
  }
};

function authLayout(card) {
  return `<main class="hero">${brand()}<section class="hero-copy"><span class="eyebrow">Built for life abroad</span><h1>Find your people.<br>Feel at home.</h1><p>Compatible roommates and trusted housing for international students and professionals—matched around the things that make living together work.</p><div class="trust-row"><span><b>✓</b> Verified community</span><span><b>✓</b> Secure sign-in</span><span><b>✓</b> Privacy first</span></div></section><section class="auth-wrap">${card}</section></main>`;
}

function renderAuth() {
  if (state.authMode === "verify") return renderVerification();
  if (state.authMode === "forgot") return renderForgotPassword();
  if (state.authMode === "reset") return renderResetPassword();
  const signup = state.authMode === "signup";
  app.innerHTML = `<main class="hero">
    ${brand()}
    <section class="hero-copy">
      <span class="eyebrow">Built for life abroad</span>
      <h1>Find your people.<br>Feel at home.</h1>
      <p>Compatible roommates and trusted housing for international students and professionals—matched around the things that make living together work.</p>
      <div class="trust-row"><span><b>✓</b> Compatibility matching</span><span><b>✓</b> Community focused</span><span><b>✓</b> Privacy first</span></div>
    </section>
    <section class="auth-wrap">
      <form class="auth-card" id="authForm">
        <div class="auth-tabs"><button type="button" class="${signup?'active':''}" data-mode="signup">Sign up</button><button type="button" class="${!signup?'active':''}" data-mode="signin">Sign in</button></div>
        <h2>${signup?'Create your account':'Welcome back'}</h2><p class="subtext">${signup?'Your next home starts with the right connection.':'Sign in to continue finding your people.'}</p>
        <div class="social-row"><button type="button" class="social-btn" data-social="Google"><span class="google-g">G</span> Continue with Google</button><button type="button" class="social-btn" data-social="Apple"><span class="apple-logo">●</span> Continue with Apple</button></div>
        <div class="or"><span>or continue with email</span></div>
        <div class="fields">
          ${signup?'<label>Full name<input name="name" required placeholder="Your full name" autocomplete="name"></label>':''}
          <label>Email address<input name="email" required type="email" placeholder="you@example.com" autocomplete="email"></label>
          <label>Password<div class="password-wrap"><input name="password" required type="password" minlength="8" placeholder="At least 8 characters" autocomplete="${signup?'new-password':'current-password'}"><button type="button" class="show-password" aria-label="Show password">Show</button></div></label>
          ${signup?'<div class="password-rules"><span>Use 8+ characters with a number and a letter.</span></div>':'<button type="button" class="text-btn" id="forgot">Forgot password?</button>'}
        </div>
        <p class="auth-error" id="authError" role="alert"></p>
        <button class="btn btn-primary btn-wide">${signup?'Create account':'Sign in'} <span>→</span></button>
        <p class="fine">By continuing, you agree to our community guidelines and privacy policy.</p>
      </form>
    </section>
  </main>`;
  document.querySelectorAll("[data-mode]").forEach(b => b.onclick = () => { state.authMode=b.dataset.mode; render(); });
  document.querySelectorAll("[data-social]").forEach(b => b.onclick = () => showToast(`${b.dataset.social} sign-in needs provider credentials. Demo mode is active.`));
  document.querySelector(".show-password").onclick = e => { const input=e.target.previousElementSibling; input.type=input.type==="password"?"text":"password"; e.target.textContent=input.type==="password"?"Show":"Hide"; };
  document.querySelector("#forgot")?.addEventListener("click", () => { state.authMode="forgot"; render(); });
  document.querySelector("#authForm").addEventListener("submit", async e => {
    e.preventDefault();
    const data = Object.fromEntries(new FormData(e.target));
    const error = document.querySelector("#authError");
    const email=data.email.trim().toLowerCase();
    if (signup) {
      if (!/(?=.*[A-Za-z])(?=.*\d).{8,}/.test(data.password)) { error.textContent="Use at least 8 characters, including a letter and a number."; return; }
      try { const result=await RoomBridgeAPI.register({name:data.name.trim(),email,password:data.password});state.pendingAuth={type:"email",accountId:result.userId,destination:email,code:result.demoCode,verificationId:result.verificationId,server:true};state.authMode="verify";render() } catch(apiError) { error.textContent=apiError.message; }
    } else {
      try { const result=await RoomBridgeAPI.login({email,password:data.password});state.user=result.user;sessionStorage.setItem("rbSession",JSON.stringify(state.user));const profile=JSON.parse(localStorage.getItem("rbUser")||"null");if(profile?.email===email)state.user={...state.user,...profile};state.screen=profile?.email===email?"dashboard":"onboard";render() } catch(apiError) { error.textContent=apiError.message; }
    }
  });
}

function renderVerification() {
  const p=state.pendingAuth;
  if (!p) { state.authMode="signup"; return render(); }
  const label=p.type==="phone"?"phone number":"email address";
  app.innerHTML=authLayout(`<form class="auth-card" id="verifyForm"><button type="button" class="back-link" id="authBack">← Back</button><div class="verify-icon">${p.type==="phone"?'◫':'✉'}</div><h2>Verify your ${p.type}</h2><p class="subtext">We sent a 6-digit code to <strong>${p.destination}</strong>.</p><div class="demo-code"><span>Demo verification code</span><strong>${p.code}</strong></div><label>Verification code<input class="otp-input" name="code" required inputmode="numeric" maxlength="6" pattern="[0-9]{6}" placeholder="000000" autocomplete="one-time-code"></label><p class="auth-error" id="authError"></p><button class="btn btn-primary btn-wide">Verify and continue</button><button type="button" class="text-btn resend" id="resend">Resend code</button></form>`);
  document.querySelector("#authBack").onclick=()=>{state.authMode="signup";state.pendingAuth=null;render()};
  document.querySelector("#resend").onclick=async()=>{try{const result=await RoomBridgeAPI.resendCode(p.verificationId);p.verificationId=result.verificationId;p.code=result.demoCode;render();showToast("A new verification code was generated")}catch(error){showToast(error.message)}};
  document.querySelector("#verifyForm").onsubmit=async e=>{e.preventDefault();const code=new FormData(e.target).get("code"),error=document.querySelector("#authError");try{const result=await RoomBridgeAPI.verify({verificationId:p.verificationId,code});state.user=result.user;sessionStorage.setItem("rbSession",JSON.stringify(state.user));state.pendingAuth=null;const profile=JSON.parse(localStorage.getItem("rbUser")||"null");if(profile?.email===state.user.email){state.user={...state.user,...profile};state.screen="dashboard"}else state.screen="onboard";render();showToast(`${p.type==='email'?'Email':'Phone'} verified successfully`)}catch(apiError){error.textContent=apiError.message}};
}

function renderForgotPassword() {
  app.innerHTML=authLayout(`<form class="auth-card" id="forgotForm"><button type="button" class="back-link" id="authBack">← Back to sign in</button><div class="verify-icon">↻</div><h2>Reset your password</h2><p class="subtext">Enter your account email and we'll send a reset code.</p><label>Email address<input name="email" required type="email" placeholder="you@example.com"></label><p class="auth-error" id="authError"></p><button class="btn btn-primary btn-wide">Send reset code</button></form>`);
  document.querySelector("#authBack").onclick=()=>{state.authMode="signin";render()};
  document.querySelector("#forgotForm").onsubmit=e=>{e.preventDefault();const email=new FormData(e.target).get("email").trim().toLowerCase();const account=authStore.users().find(u=>u.email===email);if(!account){document.querySelector("#authError").textContent="No account was found for that email.";return}state.pendingAuth={type:"reset",accountId:account.id,destination:email,code:authStore.code()};state.authMode="reset";render()};
}

function renderResetPassword() {
  const p=state.pendingAuth;if(!p){state.authMode="signin";return render()}
  app.innerHTML=authLayout(`<form class="auth-card" id="resetForm"><button type="button" class="back-link" id="authBack">← Cancel</button><h2>Choose a new password</h2><p class="subtext">Enter the demo code and a strong new password.</p><div class="demo-code"><span>Demo reset code</span><strong>${p.code}</strong></div><div class="fields"><label>Reset code<input name="code" required maxlength="6" inputmode="numeric" placeholder="000000"></label><label>New password<input name="password" required type="password" minlength="8" placeholder="8+ characters with a number"></label></div><p class="auth-error" id="authError"></p><button class="btn btn-primary btn-wide">Update password</button></form>`);
  document.querySelector("#authBack").onclick=()=>{state.pendingAuth=null;state.authMode="signin";render()};
  document.querySelector("#resetForm").onsubmit=async e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.target));const error=document.querySelector("#authError");if(d.code!==p.code){error.textContent="The reset code is incorrect.";return}if(!/(?=.*[A-Za-z])(?=.*\d).{8,}/.test(d.password)){error.textContent="Use at least 8 characters, including a letter and number.";return}const users=authStore.users();const account=users.find(u=>u.id===p.accountId);account.salt=crypto.randomUUID();account.passwordHash=await authStore.hash(d.password,account.salt);authStore.save(users);state.pendingAuth=null;state.authMode="signin";render();showToast("Password updated. You can now sign in.")};
}

function choices(name, items, selected) {
  return `<div class="choice-grid">${items.map(([value, desc]) => `<label class="choice ${selected===value?'selected':''}"><input type="radio" name="${name}" value="${value}" ${selected===value?'checked':''} required><strong>${value}</strong><small>${desc}</small></label>`).join("")}</div>`;
}

function optionList(values, selected) { return values.map(v=>`<option ${v===selected?'selected':''}>${v}</option>`).join(''); }
function importance(name, label, value="Nice to have") { return `<label>${label}<select name="${name}">${optionList(["Required","Important","Nice to have","Doesn't matter"],value)}</select></label>`; }

function renderOnboard() {
  const titles = ["What brings you here?", "Tell us what you need", "A little about you", "Build your compatibility profile"];
  let content = "";
  if (state.step === 1) content = `${choices("scenario", [["Find a new home","Find a place and roommates"],["Find a roommate","Share your current room"],["Fill an available room","Rent a room in your home"],["Find my replacement","Transfer my spot or lease"]], state.user.scenario)}`;
  if (state.step === 2) content = `<div class="grid-2">
      <label>Preferred location<input name="city" required value="${state.user.city||''}" placeholder="e.g. Jersey City, NJ"></label>
      <label>Monthly budget (USD)<input name="budget" required type="number" min="200" value="${state.user.budget||''}" placeholder="1200"></label>
      <label>Room preference<select name="room" required>${optionList(["Private room","Shared room","Either works"],state.user.room)}</select></label>
      <label>People you want to live with<select name="people" required>${optionList(["1","2","3","4+"],state.user.people)}</select></label>
      <label>Move-in date<input name="move" required type="date" value="${state.user.move||''}"></label>
      <label>Stay duration<select name="duration">${optionList(["12+ months","6–12 months","3–6 months","Flexible"],state.user.duration)}</select></label>
    </div>`;
  if (state.step === 3) content = `<div class="grid-2">
      <label>Immigration / work status<select name="status">${optionList(["International student","OPT","STEM OPT","H-1B","Other","Prefer not to say"],state.user.status)}</select></label>
      <label>Country<input name="country" required value="${state.user.country||''}" placeholder="Country you call home"></label>
      <label>Food preference<select name="diet">${optionList(["Vegetarian","Non-vegetarian","Vegan","Halal","No preference"],state.user.diet)}</select></label>
      <label>Languages<input name="languages" value="${state.user.languages||''}" placeholder="e.g. English, Hindi, Telugu"></label>
    </div><label style="margin-top:17px">Lifestyle & roommate preferences<textarea name="preferences" placeholder="Tell potential roommates about your schedule, cleanliness, pets, smoking, or anything important to you.">${state.user.preferences||''}</textarea></label>`;
  if (state.step === 4) content = `<div class="question-block"><h3>Your everyday lifestyle</h3><div class="grid-2">
      <label>Cleanliness<select name="cleanliness">${optionList(["Very tidy","Tidy","Relaxed"],state.user.cleanliness)}</select></label>
      <label>Daily schedule<select name="schedule">${optionList(["Early riser","Night owl","Flexible"],state.user.schedule)}</select></label>
      <label>Home atmosphere<select name="social">${optionList(["Quiet","Balanced","Social"],state.user.social)}</select></label>
      <label>Overnight guests<select name="guests">${optionList(["Rarely","Occasionally","Often"],state.user.guests)}</select></label>
    </div></div><div class="question-block"><h3>How important is compatibility?</h3><p>Required preferences act as hard filters. Others contribute to the match score.</p><div class="grid-2">${importance("cleanlinessWeight","Similar cleanliness",state.user.cleanlinessWeight)}${importance("scheduleWeight","Similar schedule",state.user.scheduleWeight)}${importance("socialWeight","Similar social style",state.user.socialWeight)}${importance("budgetWeight","Budget alignment",state.user.budgetWeight||"Important")}</div></div>
    <div class="question-block"><h3>Deal-breakers</h3><p>Profiles that conflict with these choices will not appear.</p><div class="deal-grid">
      <label class="check-row"><input type="checkbox" name="noSmoking" ${state.user.noSmoking?'checked':''}><span><strong>Smoke-free home</strong><small>No indoor smokers</small></span></label>
      <label class="check-row"><input type="checkbox" name="noPets" ${state.user.noPets?'checked':''}><span><strong>No pets</strong><small>Exclude pet-friendly homes</small></span></label>
      <label class="check-row"><input type="checkbox" name="dietRequired" ${state.user.dietRequired?'checked':''}><span><strong>Same food preference</strong><small>Diet must match mine</small></span></label>
      <label class="check-row"><input type="checkbox" name="rareGuests" ${state.user.rareGuests?'checked':''}><span><strong>Limited overnight guests</strong><small>Rarely or occasionally only</small></span></label>
    </div><label style="margin-top:15px">Gender preference<select name="genderPreference">${optionList(["No preference","Woman","Man","Non-binary"],state.user.genderPreference)}</select></label></div>`;
  app.innerHTML = `<main class="onboard">
    <aside class="onboard-aside">${brand()}<div class="steps">${[1,2,3,4].map((n,i)=>`<div class="step ${state.step===n?'active':''} ${state.step>n?'done':''}"><span class="step-num">${state.step>n?'✓':n}</span><div><strong>${["Your housing goal","Home preferences","About you","Compatibility"][i]}</strong><small>${["How can we help?","What works for you?","Introduce yourself","Priorities & deal-breakers"][i]}</small></div></div>`).join('')}</div></aside>
    <section class="onboard-main"><form class="form-card" id="profileForm">
      <div class="progress"><div style="width:${state.step*25}%"></div></div>
      <span class="eyebrow" style="color:var(--green)">Step ${state.step} of 4</span><h2>${titles[state.step-1]}</h2><p class="subtext">${["Choose the situation that best describes you.","These details help us find realistic, relevant matches.","Introduce yourself to potential roommates.","Tell us what makes sharing a home work for you."][state.step-1]}</p>
      ${content}
      <div class="actions">${state.step>1?'<button type="button" class="btn btn-ghost" id="back">← Back</button>':'<span></span>'}<button class="btn btn-primary">${state.step===4?'See my matches ✦':'Continue →'}</button></div>
    </form></section>
  </main>`;
  document.querySelectorAll(".choice").forEach(el => el.addEventListener("click", () => { document.querySelectorAll(".choice").forEach(x=>x.classList.remove("selected")); el.classList.add("selected"); }));
  document.querySelector("#back")?.addEventListener("click", () => { state.step--; render(); });
  document.querySelector("#profileForm").addEventListener("submit", e => {
    e.preventDefault(); const values=Object.fromEntries(new FormData(e.target)); if(state.step===4)["noSmoking","noPets","dietRequired","rareGuests"].forEach(k=>values[k]=new FormData(e.target).has(k)); Object.assign(state.user,values);
    if (state.step < 4) { state.step++; render(); }
    else { localStorage.setItem("rbUser", JSON.stringify(state.user)); RoomBridgeAPI.saveProfile({scenario:state.user.scenario,city:state.user.city,budget:Number(state.user.budget),roomType:state.user.room,moveDate:state.user.move,leaseDuration:state.user.duration,country:state.user.country,diet:state.user.diet,languages:(state.user.languages||"").split(/,\s*/),bio:state.user.preferences,lifestyle:{cleanliness:state.user.cleanliness,schedule:state.user.schedule,social:state.user.social,guests:state.user.guests},weights:{cleanliness:state.user.cleanlinessWeight,schedule:state.user.scheduleWeight,social:state.user.socialWeight,budget:state.user.budgetWeight},dealBreakers:{noSmoking:state.user.noSmoking,noPets:state.user.noPets,dietRequired:state.user.dietRequired,rareGuests:state.user.rareGuests}}).catch(()=>showToast("Profile saved locally; server sync will retry later")); state.screen="dashboard"; render(); showToast("Your profile is live — welcome to RoomBridge!"); }
  });
}

function scoreProfile(p) {
  const u=state.user||{}, conflicts=[];
  if(u.noSmoking&&p.smoking!=="No")conflicts.push("smoking conflicts with your deal-breaker");
  if(u.noPets&&p.pets!=="No pets")conflicts.push("pets conflict with your deal-breaker");
  if(u.dietRequired&&u.diet&&p.diet!==u.diet)conflicts.push("food preference must match");
  if(u.rareGuests&&p.guests==="Often")conflicts.push("overnight guest preference conflicts");
  if(u.genderPreference&&u.genderPreference!=="No preference"&&p.gender!==u.genderPreference)conflicts.push("gender preference does not match");
  const required={cleanlinessWeight:[u.cleanliness,p.cleanliness,"cleanliness"],scheduleWeight:[u.schedule,p.schedule,"schedule"],socialWeight:[u.social,p.social,"home atmosphere"]};
  Object.entries(required).forEach(([key,[a,b,label]])=>{if(u[key]==="Required"&&a&&a!==b)conflicts.push(`${label} is marked required`)});
  if(conflicts.length)return {excluded:true,conflicts,score:0,reasons:[],breakdown:[]};
  const weight=v=>({"Required":14,"Important":11,"Nice to have":6,"Doesn't matter":0}[v]??6);
  let earned=35, possible=35, breakdown=[];
  const add=(label,matched,w,detail)=>{possible+=w;if(matched)earned+=w;breakdown.push({label,matched,points:matched?w:0,max:w,detail})};
  const sameCity=!u.city||p.city.toLowerCase().includes(u.city.split(',')[0].toLowerCase());add("Location",sameCity,14,sameCity?"Preferred area matches":"Different nearby area");
  const budget=Number(u.budget)||1300,budgetClose=Math.abs(p.budget-budget)<=200;add("Budget",budgetClose,weight(u.budgetWeight||"Important"),budgetClose?"Within $200 of your budget":`$${Math.abs(p.budget-budget)} difference`);
  add("Room type",u.room===p.room||u.room==="Either works"||!u.room,8,u.room===p.room?"Same room preference":"Flexible or different");
  add("Cleanliness",!u.cleanliness||u.cleanliness===p.cleanliness,weight(u.cleanlinessWeight),`${p.cleanliness} lifestyle`);
  add("Schedule",!u.schedule||u.schedule===p.schedule,weight(u.scheduleWeight),p.schedule);
  add("Home atmosphere",!u.social||u.social===p.social,weight(u.socialWeight),p.social);
  add("Food preference",u.diet===p.diet||u.diet==="No preference"||!u.diet,7,p.diet);
  const langs=(u.languages||"").toLowerCase().split(/,\s*/).filter(Boolean),shared=p.languages.find(l=>langs.includes(l.toLowerCase()));add("Language",!!shared,5,shared?`Both speak ${shared}`:"No listed shared language");
  let score=Math.round(earned/possible*100);const feedback=state.feedback[p.id];if(feedback==="more")score+=4;if(feedback==="less")score-=8;
  const reasons=breakdown.filter(x=>x.matched&&x.max>0).sort((a,b)=>b.max-a.max).slice(0,3).map(x=>x.detail);
  return {excluded:false,score:Math.max(35,Math.min(score,98)),reasons,breakdown,conflicts:[]};
}

function buildGroups(profiles) {
  const eligible=profiles.filter(p=>!p.excluded).slice(0,6),groups=[];
  for(let a=0;a<eligible.length;a++)for(let b=a+1;b<eligible.length;b++)for(let c=b+1;c<eligible.length;c++){
    const members=[eligible[a],eligible[b],eligible[c]], cities=new Set(members.map(x=>x.city)), smoke=members.every(x=>x.smoking==="No"), clean=new Set(members.map(x=>x.cleanliness)).size<=2;
    let score=Math.round(members.reduce((s,x)=>s+x.score,0)/3)+(cities.size===1?4:0)+(smoke?2:0)+(clean?2:0);
    groups.push({id:members.map(x=>x.id).join('-'),members,score:Math.min(score,98),budget:members.reduce((s,x)=>s+x.budget,0),reasons:[cities.size===1?"same target area":"nearby locations",smoke?"smoke-free household":"compatible housing needs",clean?"similar cleanliness":"balanced lifestyles"]});
  }
  for(let a=0;a<eligible.length;a++)for(let b=a+1;b<eligible.length;b++)for(let c=b+1;c<eligible.length;c++)for(let d=c+1;d<eligible.length;d++){
    const members=[eligible[a],eligible[b],eligible[c],eligible[d]],cities=new Set(members.map(x=>x.city)),smoke=members.every(x=>x.smoking==="No"),clean=new Set(members.map(x=>x.cleanliness)).size<=2;
    let score=Math.round(members.reduce((s,x)=>s+x.score,0)/4)+(cities.size<=2?3:0)+(smoke?2:0)+(clean?2:0);
    groups.push({id:members.map(x=>x.id).join('-'),members,score:Math.min(score,98),budget:members.reduce((s,x)=>s+x.budget,0),reasons:[cities.size<=2?"close target areas":"compatible move plans",smoke?"smoke-free household":"shared housing goals",clean?"similar cleanliness":"balanced lifestyles"]});
  }
  return groups.sort((a,b)=>b.score-a.score).slice(0,4);
}

