function listingShell(content) {
  return `<div class="shell"><header class="topbar">${brand()}${mainNav('housing')}<button class="avatar avatar-button" id="securityCenter" aria-label="Account and security">${(state.user.name||'RB').split(' ').map(x=>x[0]).slice(0,2).join('').toUpperCase()}</button></header>${content}</div>`;
}
function renderListings() {
  const f=state.searchFilters, listings=demoListings.filter(l=>(state.listingCategory==="All homes"||l.category===state.listingCategory)&&l.rent<=f.budget&&(f.location==="All locations"||l.city.startsWith(f.location))&&(!f.moveBy||l.available<=f.moveBy)&&(f.roomType==="All types"||l.category===f.roomType)&&(f.lease==="Any lease"||l.lease.includes(f.lease))&&l.commutes[state.commuteTo]<=f.maxCommute);
  app.innerHTML=listingShell(`<main class="dashboard listings-page"><section class="listing-hero"><div><span class="eyebrow">Homes on RoomBridge</span><h1>Find a place that fits your life.</h1><p>Rooms, apartments, and verified lease transfers—with the details that matter before you visit.</p></div><button class="btn btn-primary" id="createListing">+ List a room</button></section><form class="advanced-search" id="searchFilters"><label>Max budget<input name="budget" type="number" value="${f.budget}" min="200"></label><label>Location<select name="location">${["All locations","Jersey City","Hoboken","Newark"].map(x=>`<option ${x===f.location?'selected':''}>${x}</option>`).join('')}</select></label><label>Move in by<input name="moveBy" type="date" value="${f.moveBy}"></label><label>Room type<select name="roomType">${["All types","Private room","Shared room","Entire apartment","Lease transfer"].map(x=>`<option ${x===f.roomType?'selected':''}>${x}</option>`).join('')}</select></label><label>Lease length<select name="lease">${["Any lease","6–12","12","Month-to-month"].map(x=>`<option ${x===f.lease?'selected':''}>${x}</option>`).join('')}</select></label><label>Max commute<select name="maxCommute">${[15,30,45,60,90].map(x=>`<option value="${x}" ${x==f.maxCommute?'selected':''}>${x} min</option>`).join('')}</select></label><button class="btn btn-primary">Search</button></form><div class="search-actions"><span><b>${listings.length}</b> suitable homes</span><button class="btn btn-ghost" id="saveSearch">☆ Save this search</button><button class="btn ${state.alertsEnabled?'btn-secondary':'btn-ghost'}" id="toggleAlerts">${state.alertsEnabled?'🔔 Alerts on':'♢ Get alerts'}</button>${state.savedSearches.length?`<span class="saved-count">${state.savedSearches.length} saved search${state.savedSearches.length>1?'es':''}</span>`:''}</div><section class="listing-toolbar"><div class="filters">${["All homes","Private room","Shared room","Entire apartment","Lease transfer"].map(x=>`<button type="button" class="filter ${state.listingCategory===x?'active':''}" data-category="${x}">${x}</button>`).join('')}</div><div class="view-toggle"><button type="button" class="${state.listingView==='grid'?'active':''}" data-list-view="grid">Grid</button><button type="button" class="${state.listingView==='map'?'active':''}" data-list-view="map">Map</button></div></section>${state.listingView==='map'?mapView(listings):`<div class="listing-grid">${listings.length?listings.map(listingCard).join(''):'<div class="empty">No homes match every filter. Try expanding your budget, date, or commute.</div>'}</div>`}</main>`);
  bindListingEvents();
}
function applyListingFilters(e){e.preventDefault();const d=Object.fromEntries(new FormData(e.target));state.searchFilters={budget:Number(d.budget),location:d.location,moveBy:d.moveBy,roomType:d.roomType,lease:d.lease,maxCommute:Number(d.maxCommute)};renderListings()}
function saveCurrentSearch(){state.savedSearches.push({id:Date.now(),name:`${state.searchFilters.location} · under $${state.searchFilters.budget}`,filters:{...state.searchFilters},created:new Date().toISOString()});localStorage.setItem('rbSearches',JSON.stringify(state.savedSearches));renderListings();showToast('Search saved — alerts can notify you about new matches')}
function toggleAlerts(){state.alertsEnabled=!state.alertsEnabled;localStorage.setItem('rbAlerts',String(state.alertsEnabled));renderListings();showToast(state.alertsEnabled?'New-match alerts enabled':'Search alerts paused')}
function listingCard(l) { const commute=l.commutes[state.commuteTo];return `<article class="listing-card"><div class="listing-media">${roomIllustration(l,true)}<span class="category-badge">${l.category}</span><span class="media-count">▧ 4 ${l.video?' · ▶ video':''}</span></div><div class="listing-info"><div class="listing-title"><div><h3>${l.title}</h3><p>⌖ ${l.area} · ${l.city}</p></div><strong>$${l.rent.toLocaleString()}<small>/mo</small></strong></div><div class="listing-facts"><span>${l.beds} bed</span><span>${l.baths} bath</span><span>${l.furnished}</span><span>${l.laundry}</span></div><div class="availability"><span><b>Available</b>${new Date(l.available+'T12:00').toLocaleDateString('en-US',{month:'short',day:'numeric'})}</span><span><b>Lease</b>${l.lease}</span><span class="commute"><b>Commute</b>${commute} min to ${state.commuteTo}</span></div><button class="btn btn-primary btn-wide" data-listing="${l.id}">View home</button></div></article>`; }
function mapView(listings){return `<div class="map-layout"><aside class="map-results"><label>Estimate commute to<select id="commuteSelect">${["NYU","Columbia University","Google NYC","Newark Penn"].map(x=>`<option ${x===state.commuteTo?'selected':''}>${x}</option>`).join('')}</select></label>${listings.map(l=>`<button class="map-result" data-listing="${l.id}"><span>${l.category}</span><strong>${l.title}</strong><small>$${l.rent}/mo · ${l.commutes[state.commuteTo]} min commute</small></button>`).join('')}</aside><div class="map-canvas"><div class="river"></div><span class="map-label manhattan">MANHATTAN</span><span class="map-label jersey">NEW JERSEY</span>${listings.map(l=>`<button class="map-pin" style="left:${l.lat}%;top:${l.lng}%" data-listing="${l.id}">$${(l.rent/1000).toFixed(1)}k</button>`).join('')}<div class="map-legend">Approximate locations · commute estimates include transit</div></div></div>`}
function bindListingEvents(){bindMainNav();document.querySelectorAll('[data-category]').forEach(b=>b.onclick=()=>{state.listingCategory=b.dataset.category;renderListings()});document.querySelectorAll('[data-list-view]').forEach(b=>b.onclick=()=>{state.listingView=b.dataset.listView;renderListings()});document.querySelectorAll('[data-listing]').forEach(b=>b.onclick=()=>openListing(Number(b.dataset.listing)));document.querySelector('#commuteSelect')?.addEventListener('change',e=>{state.commuteTo=e.target.value;renderListings()});document.querySelector('#createListing').onclick=openCreateListing;document.querySelector('#saveSearch')?.addEventListener('click',saveCurrentSearch);document.querySelector('#toggleAlerts')?.addEventListener('click',toggleAlerts);document.querySelector('#searchFilters')?.addEventListener('submit',applyListingFilters)}
function openListing(id){const l=demoListings.find(x=>x.id===id),modal=document.createElement('div');modal.className='modal-backdrop listing-backdrop';modal.innerHTML=`<div class="modal listing-modal"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">${l.category}</span><h2>${l.title}</h2><p class="subtext">${l.area} · ${l.city}</p></div><button class="close">×</button></div><div class="media-tabs"><button class="active" data-media="photos">Photos</button><button data-media="video">Video ${l.video?'':'—'}</button><button data-media="floorplan">Floor plan</button></div><div id="mediaPanel">${mediaPanel(l,'photos')}</div><div class="listing-detail-head"><strong>$${l.rent.toLocaleString()}<small>/month</small></strong><span>Available ${new Date(l.available+'T12:00').toLocaleDateString()}</span></div><div class="detail-grid"><div><b>Deposit</b><span>$${l.deposit.toLocaleString()}</span></div><div><b>Lease duration</b><span>${l.lease}</span></div><div><b>Furnishing</b><span>${l.furnished}</span></div><div><b>Utilities</b><span>${l.utilities}</span></div><div><b>Parking</b><span>${l.parking}</span></div><div><b>Laundry</b><span>${l.laundry}</span></div><div><b>Accessibility</b><span>${l.accessibility}</span></div><div><b>Commute</b><span>${l.commutes[state.commuteTo]} min to ${state.commuteTo}</span></div></div><div class="neighborhood-info"><div><b>🚆 Public transportation</b><span>${l.city.startsWith('Jersey')?'PATH station and NJ Transit buses nearby':l.city.startsWith('Hoboken')?'Hoboken Terminal, PATH, ferry, and light rail':'NJ Transit rail, PATH connections, and local buses'}</span></div><div><b>◉ Neighborhood</b><span>${l.area} · ${l.city.startsWith('Newark')?'University and dining access':'Walkable groceries, cafés, and parks'}</span></div></div><h3 class="amenity-title">Amenities</h3><div class="amenity-list">${l.amenities.map(a=>`<span>✓ ${a}</span>`).join('')}</div>${l.category==='Lease transfer'?'<button class="btn btn-secondary btn-wide" id="leaseWorkflow">Open lease replacement workflow</button>':''}<button class="btn btn-primary btn-wide" id="tourRequest">Request a tour</button></div>`;document.body.appendChild(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.onclick=e=>{if(e.target===modal)modal.remove()};modal.querySelectorAll('[data-media]').forEach(b=>b.onclick=()=>{modal.querySelectorAll('[data-media]').forEach(x=>x.classList.remove('active'));b.classList.add('active');modal.querySelector('#mediaPanel').innerHTML=mediaPanel(l,b.dataset.media)});modal.querySelector('#leaseWorkflow')?.addEventListener('click',()=>{modal.remove();openLeaseWorkflow(l.id)});modal.querySelector('#tourRequest').onclick=()=>{modal.remove();showToast(`Tour request sent to ${l.host}`)}}
