function openCreateListing(){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal" id="listingForm"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">Host on RoomBridge</span><h2>List your space</h2></div><button type="button" class="close">×</button></div><p class="subtext">Add the essentials now. Photos, video, and floor plans can be uploaded after saving.</p><div class="grid-2"><label>Listing title<input required name="title" placeholder="Bright room near transit"></label><label>Category<select name="category">${["Private room","Shared room","Entire apartment","Lease transfer"].map(x=>`<option>${x}</option>`).join('')}</select></label><label>Monthly rent<input required name="rent" type="number" min="200" placeholder="1200"></label><label>Available from<input required name="available" type="date"></label><label>Furnishing<select name="furnished"><option>Furnished</option><option>Unfurnished</option></select></label><label>Lease duration<select name="lease"><option>12 months</option><option>6–12 months</option><option>Month-to-month</option><option>Lease remainder</option></select></label></div><label style="margin-top:15px">Media<input type="file" multiple accept="image/*,video/*,.pdf"></label><button class="btn btn-primary btn-wide">Save draft listing</button></form>`;document.body.appendChild(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('#listingForm').onsubmit=e=>{e.preventDefault();modal.remove();showToast('Draft listing saved — ready for media and details')}}

