function saveConversations(){localStorage.setItem('rbConversations',JSON.stringify(state.conversations))}
function renderMessages(activeId=state.conversations[0].id){const active=state.conversations.find(c=>c.id===activeId)||state.conversations[0];active.unread=0;saveConversations();app.innerHTML=appShell('messages',`<main class="messenger"><aside class="conversation-list"><div class="conversation-title"><div><span class="eyebrow">Inbox</span><h1>Messages</h1></div><button class="new-chat" id="newGroup">+</button></div><input class="conversation-search" placeholder="Search conversations"><div>${state.conversations.map(c=>`<button class="conversation-item ${c.id===active.id?'active':''}" data-conversation="${c.id}"><span class="conversation-avatar" style="background:${c.color}">${c.initials}<i class="${c.online?'online':''}"></i></span><span><strong>${c.name}</strong><small>${c.type==='group'?(c.members||[]).join(', '):c.messages.at(-1)?.text||''}</small></span>${c.unread?`<b>${c.unread}</b>`:''}</button>`).join('')}</div></aside><section class="chat"><header class="chat-head"><div><strong>${active.name}</strong><small>${active.type==='group'?`${active.members.length} household members`:active.online?'Online now':'Usually replies within a day'}</small></div><div><button data-call="voice" title="Voice call">☎</button><button data-call="video" title="Video call">▣</button><button id="chatInfo" title="Conversation settings">•••</button></div></header><div class="starter-row"><span>Conversation starters</span>${["What is your move-in date?","How do you split chores?","Want to tour a home together?"].map(x=>`<button data-starter="${x}">${x}</button>`).join('')}</div><div class="message-thread"><div class="chat-safety">🛡 Never pay a deposit before verifying the home, host, and lease.</div>${active.blocked?'<div class="blocked-note">You blocked this conversation. Unblock to send messages.</div>':active.messages.map(m=>`<div class="bubble ${m.from==='me'?'mine':''}"><small>${active.type==='group'&&m.from!=='me'?m.from:''}</small><p>${m.text}</p><span>${m.time}${m.from==='me'?` · ${m.read?'Read':'Sent'}`:''}</span>${m.from!=='me'?'<button class="translate">Translate</button>':''}</div>`).join('')}</div><form class="composer" id="messageForm"><label class="attach" title="Share image or document">＋<input type="file" name="attachment" accept="image/*,.pdf,.doc,.docx"></label><input name="message" placeholder="Write a message…" ${active.blocked?'disabled':''}><button ${active.blocked?'disabled':''}>Send</button></form></section></main>`);bindMainNav();document.querySelectorAll('[data-conversation]').forEach(b=>b.onclick=()=>renderMessages(b.dataset.conversation));document.querySelectorAll('[data-starter]').forEach(b=>b.onclick=()=>{document.querySelector('[name=message]').value=b.dataset.starter});document.querySelectorAll('[data-call]').forEach(b=>b.onclick=()=>startCall(b.dataset.call,active));document.querySelectorAll('.translate').forEach(b=>b.onclick=()=>{const p=b.previousElementSibling.previousElementSibling;b.textContent=b.textContent==='Translate'?'Show original':'Translate';p.textContent=b.textContent==='Show original'?`[Translated] ${p.textContent}`:p.textContent.replace('[Translated] ','')});document.querySelector('#messageForm').onsubmit=e=>{e.preventDefault();const d=new FormData(e.target),text=d.get('message').trim(),file=d.get('attachment');if(!text&&!file?.name)return;const risk=scamRisk(text);if(risk.risky&&!confirm(`RoomBridge safety warning\n\n${risk.message}\n\nSend this message anyway?`))return;active.messages.push({from:'me',text:text||(file.type.startsWith('image/')?'📷 Image shared':`📎 ${file.name}`),time:new Date().toLocaleTimeString([],{hour:'numeric',minute:'2-digit'}),read:false});saveConversations();renderMessages(active.id);setTimeout(()=>{const msg=active.messages.at(-1);if(msg?.from==='me'){msg.read=true;saveConversations()}},1200)};document.querySelector('#chatInfo').onclick=()=>openChatControls(active);document.querySelector('#newGroup').onclick=createGroupConversation;}
function startCall(type,c){const modal=document.createElement('div');modal.className='modal-backdrop call-screen';modal.innerHTML=`<div class="call-card"><span class="conversation-avatar large" style="background:${c.color}">${c.initials}</span><h2>${type==='video'?'Video':'Voice'} call with ${c.name}</h2><p>Connecting securely…</p><div><button>◉</button><button>♩</button><button class="end-call">End call</button></div></div>`;document.body.appendChild(modal);modal.querySelector('.end-call').onclick=()=>modal.remove()}
function openChatControls(c){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<div class="modal"><div class="modal-head"><h2>Conversation settings</h2><button class="close">×</button></div><div class="security-options"><div class="security-row"><span class="security-symbol">✓</span><div><strong>Read receipts</strong><small>See when messages are read</small></div><span class="status-pill verified-pill">On</span></div><div class="security-row"><span class="security-symbol">⊘</span><div><strong>${c.blocked?'Unblock':'Block'} ${c.type==='group'?'conversation':c.name.split(' ')[0]}</strong><small>${c.blocked?'Resume messages':'Stop messages and calls'}</small></div><button class="text-btn" id="blockChat">${c.blocked?'Unblock':'Block'}</button></div></div></div>`;document.body.appendChild(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('#blockChat').onclick=()=>{c.blocked=!c.blocked;saveConversations();modal.remove();renderMessages(c.id);showToast(c.blocked?'Conversation blocked':'Conversation unblocked')}}
function createGroupConversation(){const id='group'+Date.now();state.conversations.unshift({id,type:'group',name:'New household group',initials:'NH',color:'#dcecdf',online:true,blocked:false,unread:0,members:['You','Ananya','Priya'],messages:[{from:'me',text:'I created this group so we can plan our housing search together.',time:'Now',read:false}]});saveConversations();renderMessages(id)}

function renderHousehold(){const h=state.household,members=h.members.map(id=>demoProfiles.find(p=>p.id===id)),listings=h.shortlist.map(id=>demoListings.find(l=>l.id===id));app.innerHTML=appShell('household',`<main class="dashboard household-page"><section class="household-hero"><div><span class="eyebrow">Prospective household</span><h1>${h.name}</h1><p>${members.length+1} people planning a home together · ${Math.round(members.reduce((s,m)=>s+scoreProfile(m).score,0)/members.length)}% group compatibility</p></div><button class="btn btn-primary" id="inviteMatch">+ Invite a match</button></section><div class="household-stats"><div><span>Combined budget</span><strong>$${(members.reduce((s,m)=>s+m.budget,0)+(Number(state.user.budget)||1300)).toLocaleString()}</strong><small>per month</small></div><div><span>Target area</span><strong>Jersey City</strong><small>near PATH transit</small></div><div><span>Move window</span><strong>Aug 1–15</strong><small>2026</small></div><div><span>Compatibility</span><strong>89%</strong><small>strong household</small></div></div><section class="household-section"><div class="section-head"><h2>Household members</h2><span>Invite, compare, and plan</span></div><div class="member-grid"><div class="member-plan you"><div class="person-avatar">${(state.user.name||'You').slice(0,2).toUpperCase()}</div><strong>${state.user.name||'You'}</strong><small>$${state.user.budget||1300} budget</small><span>${state.user.cleanliness||'Tidy'} · ${state.user.schedule||'Flexible'}</span></div>${members.map(m=>`<div class="member-plan"><div class="person-avatar" style="background:${m.color}">${m.initials}</div><strong>${m.name}</strong><small>$${m.budget} budget</small><span>${m.cleanliness} · ${m.schedule}</span><button data-remove-member="${m.id}">Remove</button></div>`).join('')}</div></section><section class="household-section"><div class="section-head"><h2>Shared property shortlist</h2><span>${listings.length} homes · everyone can vote</span></div><div class="shortlist">${listings.map(l=>shortlistCard(l,h,members)).join('')}</div></section><section class="household-section"><div class="section-head"><h2>Room assignments & rent split</h2><span>Estimated household total: $${Object.values(h.split).reduce((a,b)=>a+b,0)}</span></div><div class="rent-table">${members.map(m=>`<div><span class="conversation-avatar" style="background:${m.color}">${m.initials}</span><strong>${m.name}</strong><select data-room="${m.id}">${['Primary bedroom','Bedroom 2','Flex room','Shared room'].map(x=>`<option ${h.rooms[m.id]===x?'selected':''}>${x}</option>`).join('')}</select><label>$ <input data-split="${m.id}" type="number" value="${h.split[m.id]||m.budget}"></label></div>`).join('')}<button class="btn btn-primary" id="savePlan">Save household plan</button></div></section></main>`);bindMainNav();document.querySelectorAll('[data-vote]').forEach(b=>b.onclick=()=>{const [listing,id]=b.dataset.vote.split('-');h.votes[listing]??={};h.votes[listing][id]=b.dataset.choice;saveHousehold();renderHousehold()});document.querySelectorAll('[data-remove-member]').forEach(b=>b.onclick=()=>{h.members=h.members.filter(id=>id!==Number(b.dataset.removeMember));saveHousehold();renderHousehold()});document.querySelector('#inviteMatch').onclick=inviteToHousehold;document.querySelector('#savePlan').onclick=()=>{document.querySelectorAll('[data-room]').forEach(x=>h.rooms[x.dataset.room]=x.value);document.querySelectorAll('[data-split]').forEach(x=>h.split[x.dataset.split]=Number(x.value));saveHousehold();renderHousehold();showToast('Room assignments and rent split saved')};}
function shortlistCard(l,h,members){const votes=h.votes[l.id]||{},yes=Object.values(votes).filter(x=>x==='yes').length;return `<article class="shortlist-card"><div class="shortlist-art">${roomIllustration(l,true)}</div><div><span class="tag">${l.category}</span><h3>${l.title}</h3><p>$${l.rent}/mo · ${l.area} · ${l.beds} bedroom</p><strong>${yes} yes vote${yes===1?'':'s'}</strong><div class="vote-members"><span>Your vote: ${votes.me||'—'}</span>${members.map(m=>`<span title="${m.name}">${m.initials}: ${votes[m.id]||'—'}</span>`).join('')}</div><div class="vote-actions"><button data-vote="${l.id}-me" data-choice="yes">Like</button><button data-vote="${l.id}-me" data-choice="maybe">Maybe</button><button data-vote="${l.id}-me" data-choice="no">Pass</button></div></div></article>`}
function saveHousehold(){localStorage.setItem('rbHousehold',JSON.stringify(state.household))}
function inviteToHousehold(){const available=demoProfiles.filter(p=>!state.household.members.includes(p.id));if(!available.length)return showToast('Everyone is already invited');state.household.members.push(available[0].id);state.household.rooms[available[0].id]='Shared room';state.household.split[available[0].id]=available[0].budget;saveHousehold();renderHousehold();showToast(`${available[0].name} invited to the household`)}

function openLeaseWorkflow(listingId=104){const l=demoListings.find(x=>x.id===listingId),data=JSON.parse(localStorage.getItem('rbLeaseWorkflow')||'null')||{type:'Lease assignment',replacement:'2026-08-15',fee:350,approval:'Reviewing applicant',steps:{details:true,candidate:true,documents:false,landlord:false,signing:false}};const modal=document.createElement('div');modal.className='modal-backdrop listing-backdrop';modal.innerHTML=`<div class="modal lease-modal"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">Lease handoff</span><h2>${l.title}</h2></div><button class="close">×</button></div><div class="lease-summary"><label>Transfer type<select id="leaseType">${['Sublease','Lease assignment','Roommate replacement'].map(x=>`<option ${x===data.type?'selected':''}>${x}</option>`).join('')}</select></label><label>Replacement date<input id="replacementDate" type="date" value="${data.replacement}"></label><label>Transfer fees ($)<input id="transferFee" type="number" value="${data.fee}"></label><label>Landlord status<select id="approval">${['Not contacted','Awaiting response','Reviewing applicant','Approved','Changes requested'].map(x=>`<option ${x===data.approval?'selected':''}>${x}</option>`).join('')}</select></label></div><div class="workflow-people"><div><span>Outgoing tenant</span><strong>Priya Shah</strong><small>Preparing handoff</small></div><div><span>Incoming tenant</span><strong>Candidate invited</strong><small>Application in progress</small></div><div><span>Landlord</span><strong>Hudson Property LLC</strong><small>${data.approval}</small></div></div><h3>Handoff checklist</h3><div class="lease-steps">${[['details','Transfer details'],['candidate','Incoming tenant application'],['documents','Secure lease documents'],['landlord','Landlord approval'],['signing','Sign assignment and hand over keys']].map(([k,v])=>`<label><input type="checkbox" data-lease-step="${k}" ${data.steps[k]?'checked':''}><span><strong>${v}</strong><small>${data.steps[k]?'Completed':'Action required'}</small></span></label>`).join('')}</div><label class="secure-upload">Secure documents<input type="file" multiple accept=".pdf,.doc,.docx,image/*"><span>🔒 Files are shared only with approved participants</span></label><button class="btn btn-primary btn-wide" id="saveLease">Save lease workflow</button></div>`;document.body.appendChild(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('#saveLease').onclick=()=>{data.type=modal.querySelector('#leaseType').value;data.replacement=modal.querySelector('#replacementDate').value;data.fee=Number(modal.querySelector('#transferFee').value);data.approval=modal.querySelector('#approval').value;modal.querySelectorAll('[data-lease-step]').forEach(x=>data.steps[x.dataset.leaseStep]=x.checked);localStorage.setItem('rbLeaseWorkflow',JSON.stringify(data));modal.remove();showToast('Lease handoff progress saved')}}

function renderDashboard() {
  if(state.discovery==="housing") return renderListings();
  const first=(state.user.name||"there").split(" ")[0];
  const scored=demoProfiles.map(p=>({...p,...scoreProfile(p)})),excluded=scored.filter(p=>p.excluded).length;
  const filtered=scored.filter(p=>!p.excluded).sort((a,b)=>b.score-a.score).filter(p=> state.filter==="All matches" || (state.filter==="Under budget"&&p.budget<=Number(state.user.budget||1300)) || (state.filter==="Private room"&&p.room==="Private room") || (state.filter==="Saved"&&state.saved.includes(p.id)));
  const groups=buildGroups(scored);
  app.innerHTML=`<div class="shell"><header class="topbar">${brand()}${mainNav('roommates')}<button class="avatar avatar-button" id="securityCenter" aria-label="Account and security">${(state.user.name||'RB').split(' ').map(x=>x[0]).slice(0,2).join('').toUpperCase()}</button></header>
    <main class="dashboard"><section class="welcome"><div><h1>Good to see you, ${first}.</h1><p>Recommendations adapt as you tell us what works.</p></div><div class="view-toggle"><button class="${state.matchView==='people'?'active':''}" data-view="people">People</button><button class="${state.matchView==='groups'?'active':''}" data-view="groups">Groups of 3+</button></div></section>
    ${state.matchView==='people'?`<div class="filters filter-bar">${["All matches","Under budget","Private room","Saved"].map(f=>`<button class="filter ${state.filter===f?'active':''}" data-filter="${f}">${f}</button>`).join('')}<span class="deal-note">${excluded?`✓ ${excluded} conflict${excluded>1?'s':''} filtered by your deal-breakers`:"✓ Deal-breakers applied"}</span></div>`:''}
    <div class="content-grid"><section><div class="section-head"><h2>${state.matchView==='groups'?'Compatible roommate groups':'Your best matches'} <span style="color:var(--green)">✦</span></h2><span>${state.matchView==='groups'?groups.length+' groups':filtered.length+' people'}</span></div><div class="cards ${state.matchView==='groups'?'group-cards':''}">${state.matchView==='groups'?(groups.length?groups.map(groupCard).join(''):'<div class="empty">Complete your compatibility profile to build groups.</div>'):(filtered.length?filtered.map(profileCard).join(''):'<div class="empty">No matches in this view yet. Try another filter.</div>')}</div></section>
    <aside class="sidebar"><div class="side-card"><h3>Trust & verification</h3><div class="verification-list"><span><b class="verified">✓</b> Email verified</span><span><b class="${state.user.phoneVerified?'verified':'pending'}">${state.user.phoneVerified?'✓':'!'}</b> Phone ${state.user.phoneVerified?'verified':'not verified'}</span><span><b class="${state.user.institutionVerified?'verified':'pending'}">${state.user.institutionVerified?'✓':'!'}</b> School or employer ${state.user.institutionVerified?'verified':'optional'}</span></div><button class="btn btn-secondary btn-wide" id="manageSecurity">Manage verification</button></div>
    <div class="side-card"><h3>Stay safe on RoomBridge</h3><div class="safe-list"><div class="safe-item"><span class="safe-icon">✓</span><span>Meet by video before committing.</span></div><div class="safe-item"><span class="safe-icon">$</span><span>Never send money before viewing a home.</span></div><div class="safe-item"><span class="safe-icon">⌂</span><span>Confirm the lease and landlord.</span></div></div></div></aside></div></main></div>`;
  document.querySelectorAll("[data-filter]").forEach(b=>b.onclick=()=>{state.filter=b.dataset.filter;render()});
  document.querySelectorAll("[data-view]").forEach(b=>b.onclick=()=>{state.matchView=b.dataset.view;render()});
  document.querySelectorAll("[data-save]").forEach(b=>b.onclick=()=>toggleSave(Number(b.dataset.save)));
  document.querySelectorAll("[data-connect]").forEach(b=>b.onclick=()=>openConnect(Number(b.dataset.connect)));
  document.querySelectorAll("[data-explain]").forEach(b=>b.onclick=()=>openExplanation(Number(b.dataset.explain)));
  document.querySelectorAll("[data-feedback]").forEach(b=>b.onclick=()=>setFeedback(Number(b.dataset.id),b.dataset.feedback));
  document.querySelectorAll("[data-report-user]").forEach(b=>b.onclick=()=>openReportCenter());
  document.querySelectorAll("[data-group]").forEach(b=>b.onclick=()=>showToast("Group introduction request sent!"));
  document.querySelector("#editProfile")?.addEventListener("click",()=>{state.step=1;state.screen="onboard";render()});
  bindMainNav();
  document.querySelector("#manageSecurity").onclick=openSecurityCenter;
}

function profileCard(p) {
  return `<article class="profile-card"><div class="card-top"><div class="person-avatar" style="background:${p.color}">${p.initials}</div><div class="person"><h3>${p.name}, ${p.age}</h3><p>✓ Community verified · ${p.country}</p><p>${icon('pin')} ${p.city}</p></div><button class="match" data-explain="${p.id}" aria-label="Explain ${p.score}% match">${p.score}%</button></div><div class="card-body"><div class="need">${p.need}</div><div class="meta"><div>Monthly budget<strong>$${p.budget.toLocaleString()}</strong></div><div>Move-in<strong>${p.move}</strong></div><div>Room type<strong>${p.room}</strong></div><div>Lifestyle<strong>${p.schedule}</strong></div></div><div class="tags">${[p.diet,p.cleanliness,p.guests+' guests',...p.languages.slice(0,1)].map(t=>`<span class="tag">${t}</span>`).join('')}</div><button class="why" data-explain="${p.id}">✦ Why you match: ${p.reasons.join(" · ")} →</button><div class="feedback-row"><span>Improve recommendations</span><button class="${state.feedback[p.id]==='more'?'selected':''}" data-feedback="more" data-id="${p.id}">More like this</button><button class="${state.feedback[p.id]==='less'?'selected':''}" data-feedback="less" data-id="${p.id}">Less like this</button><button data-report-user="${p.id}">Report</button></div><div class="card-actions"><button class="btn ${state.saved.includes(p.id)?'btn-secondary':'btn-ghost'}" data-save="${p.id}">${state.saved.includes(p.id)?'♥ Saved':'♡ Save'}</button><button class="btn btn-primary" data-connect="${p.id}">Connect</button></div></div></article>`;
}

function groupCard(g) { return `<article class="profile-card group-card"><div class="group-head"><div class="avatar-stack">${g.members.map(m=>`<span style="background:${m.color}">${m.initials}</span>`).join('')}</div><div class="match">${g.score}%</div></div><div class="card-body"><h3>${g.members.map(m=>m.name.split(' ')[0]).join(', ')}</h3><p class="subtext">Potential household of 3 · Combined budget $${g.budget.toLocaleString()}</p><div class="group-members">${g.members.map(m=>`<div><span>${m.initials}</span><p><strong>${m.name}</strong><small>${m.city} · $${m.budget}</small></p></div>`).join('')}</div><p class="why">✦ Group strengths: ${g.reasons.join(' · ')}</p><button class="btn btn-primary btn-wide" data-group="${g.id}">Start a group conversation</button></div></article>`; }

function setFeedback(id,value){state.feedback[id]=state.feedback[id]===value?null:value;localStorage.setItem("rbFeedback",JSON.stringify(state.feedback));render();showToast("Thanks — your recommendations were updated")}
function openExplanation(id){const p={...demoProfiles.find(x=>x.id===id),...scoreProfile(demoProfiles.find(x=>x.id===id))};const modal=document.createElement("div");modal.className="modal-backdrop";modal.innerHTML=`<div class="modal"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">Transparent matching</span><h2>${p.score}% match with ${p.name.split(' ')[0]}</h2></div><button class="close">×</button></div><p class="subtext">Scores use only the preferences you provided. Required choices filter conflicts before scoring.</p><div class="score-breakdown">${p.breakdown.filter(x=>x.max>0).map(x=>`<div><span>${x.matched?'✓':'–'} ${x.label}<small>${x.detail}</small></span><strong>${x.points}/${x.max}</strong></div>`).join('')}</div><div class="explain-note">Feedback can slightly reorder results, but never overrides your deal-breakers.</div></div>`;document.body.appendChild(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.onclick=e=>{if(e.target===modal)modal.remove()};}

function toggleSave(id) { state.saved=state.saved.includes(id)?state.saved.filter(x=>x!==id):[...state.saved,id]; localStorage.setItem("rbSaved",JSON.stringify(state.saved)); render(); showToast(state.saved.includes(id)?"Profile saved":"Removed from saved"); }
function openConnect(id) {
  const p=demoProfiles.find(x=>x.id===id);
  const modal=document.createElement("div"); modal.className="modal-backdrop";
  modal.innerHTML=`<div class="modal"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">Start a conversation</span><h2>Connect with ${p.name.split(' ')[0]}</h2></div><button class="close">×</button></div><p class="subtext">A thoughtful introduction gets better replies.</p><div class="message-box">Hi ${p.name.split(' ')[0]}! I saw that we're both looking around ${p.city.split(',')[0]} and our housing preferences seem compatible. Would you be open to chatting about your plans?</div><label>Add a personal note<textarea id="note" placeholder="Mention your move date, schedule, or what matters to you..."></textarea></label><button class="btn btn-primary btn-wide" id="send">Send connection request →</button></div>`;
  document.body.appendChild(modal); modal.querySelector(".close").onclick=()=>modal.remove(); modal.onclick=e=>{if(e.target===modal)modal.remove()}; modal.querySelector("#send").onclick=()=>{modal.remove();showToast(`Connection request sent to ${p.name.split(' ')[0]}!`)};
}
function openSecurityCenter() {
  const modal=document.createElement("div");modal.className="modal-backdrop";
  modal.innerHTML=`<div class="modal"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">Account</span><h2>Security & verification</h2></div><button class="close">×</button></div><div class="account-email">Signed in as <strong>${state.user.email}</strong></div><div class="security-options"><div class="security-row"><span class="security-symbol">✉</span><div><strong>Email address</strong><small>${state.user.email} · Verified</small></div><b class="status-pill verified-pill">Verified</b></div><div class="security-row"><span class="security-symbol">◫</span><div><strong>Phone number</strong><small>${state.user.phoneVerified?(state.user.phone||'Verified'):'Protect your account and build trust'}</small></div><button class="text-btn" id="verifyPhone">${state.user.phoneVerified?'Update':'Verify'}</button></div><div class="security-row"><span class="security-symbol">⌂</span><div><strong>School or employer</strong><small>${state.user.institutionVerified?'Institutional email verified':'Optional community verification'}</small></div><button class="text-btn" id="verifyInstitution">${state.user.institutionVerified?'Update':'Verify'}</button></div></div><button class="btn btn-ghost btn-wide" id="signOut">Sign out</button></div>`;
  document.body.appendChild(modal);const close=()=>modal.remove();modal.querySelector(".close").onclick=close;modal.onclick=e=>{if(e.target===modal)close()};
  modal.querySelector("#signOut").onclick=()=>{sessionStorage.removeItem("rbSession");state.user=null;state.screen="auth";state.authMode="signin";close();render();showToast("You have been signed out")};
  modal.querySelector("#verifyPhone").onclick=()=>openVerificationInput("phone",modal);
  modal.querySelector("#verifyInstitution").onclick=()=>openVerificationInput("institution",modal);
}
function openVerificationInput(type, previousModal) {
  previousModal.remove();const isPhone=type==="phone";const modal=document.createElement("div");modal.className="modal-backdrop";
  modal.innerHTML=`<form class="modal" id="extraVerify"><div class="modal-head"><div><span class="eyebrow" style="color:var(--green)">Optional verification</span><h2>${isPhone?'Verify your phone':'Verify school or employer'}</h2></div><button type="button" class="close">×</button></div><p class="subtext">${isPhone?'We’ll use this for account security and never show it publicly.':'Use an official .edu or work email. Your address stays private.'}</p><label>${isPhone?'Phone number':'Institutional email'}<input name="destination" required ${isPhone?'type="tel" placeholder="+1 201 555 0123"':'type="email" placeholder="you@university.edu"'}></label><p class="auth-error" id="authError"></p><button class="btn btn-primary btn-wide">Send verification code</button></form>`;document.body.appendChild(modal);modal.querySelector(".close").onclick=()=>modal.remove();
  modal.querySelector("#extraVerify").onsubmit=e=>{e.preventDefault();const destination=new FormData(e.target).get("destination").trim();if(!isPhone&&!/(\.edu$|\.(ac|edu)\.[a-z]{2}$|@[a-z0-9.-]+\.[a-z]{2,}$)/i.test(destination)){modal.querySelector("#authError").textContent="Enter a valid university or employer email.";return}const code=authStore.code();modal.innerHTML=`<form class="modal-inner" id="codeForm"><div class="modal-head"><h2>Enter verification code</h2><button type="button" class="close">×</button></div><p class="subtext">Code sent to <strong>${destination}</strong>.</p><div class="demo-code"><span>Demo verification code</span><strong>${code}</strong></div><label>6-digit code<input name="code" required maxlength="6" inputmode="numeric" placeholder="000000"></label><p class="auth-error" id="authError"></p><button class="btn btn-primary btn-wide">Complete verification</button></form>`;modal.querySelector(".close").onclick=()=>modal.remove();modal.querySelector("#codeForm").onsubmit=ev=>{ev.preventDefault();if(new FormData(ev.target).get("code")!==code){modal.querySelector("#authError").textContent="That code is incorrect.";return}const users=authStore.users();const account=users.find(u=>u.id===state.user.id);if(isPhone){account.phone=destination;account.phoneVerified=true;state.user.phone=destination;state.user.phoneVerified=true}else{account.institutionEmail=destination;account.institutionVerified=true;state.user.institutionVerified=true}authStore.save(users);sessionStorage.setItem("rbSession",JSON.stringify(state.user));const profile=JSON.parse(localStorage.getItem("rbUser")||"{}");localStorage.setItem("rbUser",JSON.stringify({...profile,...state.user}));modal.remove();render();showToast(`${isPhone?'Phone':'Institution'} verified successfully`)};};
}
function showToast(msg){const t=document.querySelector("#toast");t.textContent=msg;t.classList.add("show");setTimeout(()=>t.classList.remove("show"),2800)}
render();
